import React, { useState } from "react";

const SearchBar = ({ onSearch, onCategoryChange }) => {

  // 🔹 Categories
  const categories = ["All", "Personal", "Work", "Study", "Health", "Finance", "All", "Personal", "Work", "Study", "Health", "Finance"];

  // 🔹 State
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");

  // 🔹 Search handler
  const handleSearch = (e) => {
    const value = e.target.value;
    setSearch(value);
    onSearch && onSearch(value);
  };

  // 🔹 Category handler
  const handleCategory = (cat) => {
    setSelectedCategory(cat);
    onCategoryChange && onCategoryChange(cat);
  };

  return (
    <div className="w-full space-y-4">

      {/* 🔍 Search Input */}
      <div className="w-full">
        <input
          type="text"
          placeholder="🔍 Search tasks..."
          value={search}
          onChange={handleSearch}
          className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white placeholder-white/60 focus:outline-none focus:ring-2 focus:ring-white/30"
        />
      </div>



    </div>
  );
};

export default SearchBar;
